"use client";

import dynamic from "next/dynamic";
import {
  ErrorPrimitive,
  MessagePrimitive,
  ThreadPrimitive,
} from "@assistant-ui/react";
import { AlertTriangleIcon } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import type { InlineCommandResult } from "@/lib/types";

const MarkdownRenderer = dynamic(
  () => import("@/components/chat/markdown-renderer").then((mod) => mod.MarkdownRenderer),
  {
    loading: () => <div className="text-sm leading-6 text-foreground/90">Loading response…</div>,
  },
);

const CommandResultCard = dynamic(
  () => import("@/components/chat/command-result-card").then((mod) => mod.CommandResultCard),
  {
    loading: () => <CommandLoadingCard label="Loading command result" />,
  },
);

export function MessageList({
  onRetry,
}: Readonly<{
  onRetry: () => void;
}>) {
  return (
    <ThreadPrimitive.Messages
      components={{
        UserMessage,
        AssistantMessage: () => <AssistantMessage onRetry={onRetry} />,
        SystemMessage,
      }}
    />
  );
}

function UserMessage() {
  return (
    <MessagePrimitive.Root className="flex justify-end px-1">
      <div className="max-w-[85%] rounded-[1.4rem] bg-primary px-4 py-3 text-sm text-primary-foreground shadow-sm">
        <MessagePrimitive.Parts>
          {({ part }) => {
            if (part.type !== "text") return null;
            return <div className="whitespace-pre-wrap leading-6">{part.text}</div>;
          }}
        </MessagePrimitive.Parts>
      </div>
    </MessagePrimitive.Root>
  );
}

function AssistantMessage({ onRetry }: Readonly<{ onRetry: () => void }>) {
  return (
    <MessagePrimitive.Root className="px-1">
      <div className="max-w-[92%] space-y-3">
        <div className="flex items-center gap-2 pl-1">
          <Badge variant="secondary">Crew</Badge>
        </div>
        <div className="rounded-[1.4rem] border border-border/80 bg-white/95 px-4 py-4 shadow-sm">
          <MessagePrimitive.Parts>
            {({ part }) => {
              if (part.type === "text") {
                return <MarkdownRenderer markdown={part.text} />;
              }

              if (part.type === "data" && part.name === "command-loading") {
                const label =
                  typeof part.data === "object" &&
                  part.data &&
                  "label" in part.data &&
                  typeof part.data.label === "string"
                    ? part.data.label
                    : "Running command";
                return <CommandLoadingCard label={label} />;
              }

              if (part.type === "data" && part.name === "command-result") {
                return <CommandResultCard result={part.data as InlineCommandResult} />;
              }

              return null;
            }}
          </MessagePrimitive.Parts>
          <MessagePrimitive.Error>
            <ErrorPrimitive.Root className="mt-4 rounded-2xl border border-destructive/20 bg-destructive/5 px-4 py-3">
              <div className="flex items-start gap-3">
                <AlertTriangleIcon className="mt-0.5 size-4 text-destructive" />
                <div className="space-y-3">
                  <ErrorPrimitive.Message />
                  <Button variant="outline" size="sm" onClick={onRetry}>
                    Retry last turn
                  </Button>
                </div>
              </div>
            </ErrorPrimitive.Root>
          </MessagePrimitive.Error>
        </div>
      </div>
    </MessagePrimitive.Root>
  );
}

function SystemMessage() {
  return (
    <MessagePrimitive.Root className="px-1">
      <div className="max-w-[92%] rounded-[1.4rem] border border-dashed border-border/80 bg-white/75 px-4 py-3 text-sm text-muted-foreground">
        <MessagePrimitive.Parts>
          {({ part }) => {
            if (part.type !== "text") return null;
            return <div className="whitespace-pre-wrap leading-6">{part.text}</div>;
          }}
        </MessagePrimitive.Parts>
      </div>
    </MessagePrimitive.Root>
  );
}

function CommandLoadingCard({ label }: Readonly<{ label: string }>) {
  return (
    <div className="rounded-[1.2rem] border border-dashed border-border/80 bg-white/80 px-4 py-4">
      <p className="text-sm font-medium">{label}</p>
      <p className="mt-1 text-xs text-muted-foreground">Running read-only command</p>
    </div>
  );
}
